#include <stdio.h>
#include <math.h>
int isPerfectSquare(int n) {
    int sqrt_n = sqrt(n);
    return sqrt_n * sqrt_n == n;
}
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N, Q;
        scanf("%d %d", &N, &Q);
        int A[N];
        for (int i = 0; i < N; i++) {
            scanf("%d", &A[i]);
        }
        while (Q--) {
            int L, R;
            scanf("%d %d", &L, &R);
            int count = 0;
            for (int i = L - 1; i < R; i++) {
                int and = A[i];
                for (int j = i; j < R; j++) {
                    and &= A[j];
                    if (isPerfectSquare(and)) {
                        count++;
                    }
                }
            }
            printf("%d\n", count);
        }
    }
    return 0;
}

