import java.util.Scanner;
public class Main {
    public static boolean isPerfectSquare(int n) {
        int sqrt_n = (int) Math.sqrt(n);
        return sqrt_n * sqrt_n == n;
    }
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int N = sc.nextInt();
            int Q = sc.nextInt();
            int[] A = new int[N];
            for (int i = 0; i < N; i++) {
                A[i] = sc.nextInt();
            }
            while (Q-- > 0) {
                int L = sc.nextInt();
                int R = sc.nextInt();
                int count = 0;
                for (int i = L - 1; i < R; i++) {
                    int and = A[i];
                    for (int j = i; j < R; j++) {
                        and &= A[j];
                        if (isPerfectSquare(and)) {
                            count++;
                        }
                    }
                }
                System.out.println(count);
            }
        }
    }
}

